"use client";

import { Menu } from "lucide-react";
import { useState } from "react";
import { Logo } from "./logo";
import { Link } from "./marketing-link";
import { PlusGrid, PlusGridItem, PlusGridRow } from "./plus-grid";

const links: { href: string; label: string }[] = [];

function DesktopNav({ variant }: { variant: "light" | "dark" }) {
  return (
    <nav className="relative hidden lg:flex">
      {links.map(({ href, label }) => (
        <PlusGridItem className="relative flex" key={href} variant={variant}>
          <Link
            className={`flex items-center px-4 py-3 font-medium text-base ${variant === "dark" ? "text-white" : "text-foreground"} bg-blend-multiply hover:bg-black/2.5`}
            href={href}
          >
            {label}
          </Link>
        </PlusGridItem>
      ))}
    </nav>
  );
}

function MobileNavButton({
  variant,
  onClick,
}: {
  variant: "light" | "dark";
  onClick: () => void;
}) {
  return (
    <button
      aria-label="Open main menu"
      className="flex size-12 items-center justify-center self-center rounded-lg hover:bg-black/5 lg:hidden"
      onClick={onClick}
      type="button"
    >
      <Menu
        className={`size-6 ${variant === "dark" ? "text-white" : "text-foreground"}`}
      />
    </button>
  );
}

function MobileNav({
  variant,
  open,
}: {
  variant: "light" | "dark";
  open: boolean;
}) {
  if (!open) {
    return null;
  }

  return (
    <div className="lg:hidden">
      <div className="flex flex-col gap-6 py-4">
        {links.map(({ href, label }) => (
          <div key={href}>
            <Link
              className={`font-medium text-base ${variant === "dark" ? "text-white" : "text-foreground"}`}
              href={href}
            >
              {label}
            </Link>
          </div>
        ))}
      </div>
      <div className="absolute left-1/2 w-screen -translate-x-1/2">
        <div
          className={`absolute inset-x-0 top-0 border-t ${variant === "dark" ? "border-white/10" : "border-black/5"}`}
        />
        <div
          className={`absolute inset-x-0 top-2 border-t ${variant === "dark" ? "border-white/10" : "border-black/5"}`}
        />
      </div>
    </div>
  );
}

export function Navbar({
  banner,
  variant = "light",
}: {
  banner?: React.ReactNode;
  variant?: "light" | "dark";
}) {
  const [open, setOpen] = useState(false);

  return (
    <header className="pt-12 sm:pt-16">
      <PlusGrid>
        <PlusGridRow
          className="relative flex justify-between"
          variant={variant}
        >
          <div className="relative flex gap-6">
            <PlusGridItem className="py-3" variant={variant}>
              <Link href="/" title="Home">
                <Logo
                  className="inline-block h-6"
                  fill={variant === "dark" ? "white" : "black"}
                />
              </Link>
            </PlusGridItem>
            {banner && (
              <div className="relative hidden items-center py-3 lg:flex">
                {banner}
              </div>
            )}
          </div>
          <DesktopNav variant={variant} />
          <MobileNavButton onClick={() => setOpen(!open)} variant={variant} />
        </PlusGridRow>
      </PlusGrid>
      <MobileNav open={open} variant={variant} />
    </header>
  );
}

import { Container } from "./container";
import { Logo } from "./logo";
import { Link } from "./marketing-link";
import { PlusGrid, PlusGridItem, PlusGridRow } from "./plus-grid";

function SitemapHeading({ children }: { children: React.ReactNode }) {
  return (
    <h3 className="font-medium text-foreground/50 text-sm/6">{children}</h3>
  );
}

function SitemapLinks({ children }: { children: React.ReactNode }) {
  return <ul className="mt-6 space-y-4 text-sm/6">{children}</ul>;
}

function SitemapLink(props: React.ComponentPropsWithoutRef<typeof Link>) {
  return (
    <li>
      <Link
        {...props}
        className="font-medium text-foreground hover:text-foreground/75"
      />
    </li>
  );
}

function Sitemap() {
  return (
    <div>
      <SitemapHeading>Product</SitemapHeading>
      <SitemapLinks>
        <SitemapLink href="/#faq">FAQs</SitemapLink>
      </SitemapLinks>
    </div>
  );
}

function SocialIconX(props: React.ComponentPropsWithoutRef<"svg">) {
  return (
    <svg aria-hidden="true" fill="currentColor" viewBox="0 0 16 16" {...props}>
      <path d="M12.6 0h2.454l-5.36 6.778L16 16h-4.937l-3.867-5.594L2.771 16H.316l5.733-7.25L0 0h5.063l3.495 5.114L12.6 0zm-.86 14.376h1.36L4.323 1.539H2.865l8.875 12.837z" />
    </svg>
  );
}

function SocialIconYouTube(props: React.ComponentPropsWithoutRef<"svg">) {
  return (
    <svg
      aria-hidden="true"
      fill="currentColor"
      viewBox="0 0 576 512"
      {...props}
    >
      <path d="M549.7 124.1c-6.3-23.7-24.8-42.3-48.3-48.6C458.8 64 288 64 288 64S117.2 64 74.6 75.5c-23.5 6.3-42 24.9-48.3 48.6-11.4 42.9-11.4 132.3-11.4 132.3s0 89.4 11.4 132.3c6.3 23.7 24.8 41.5 48.3 47.8C117.2 448 288 448 288 448s170.8 0 213.4-11.5c23.5-6.3 42-24.2 48.3-47.8 11.4-42.9 11.4-132.3 11.4-132.3s0-89.4-11.4-132.3zm-317.5 213.5V175.2l142.7 81.2-142.7 81.2z" />
    </svg>
