  --color-ht-red-800: oklch(0.542 0.246 20.005);
  --color-ht-red-900: oklch(0.46 0.208 20);
  --color-ht-red-950: oklch(0.419 0.1 20);

  /* ht-green (hue: 147) */
  --color-ht-green-50: oklch(0.99 0.009 147);
  --color-ht-green-100: oklch(0.98 0.027 147);
  --color-ht-green-200: oklch(0.965 0.058 147);
