() => {
  const h1 = document.querySelector('h1');
  const footnote = document.querySelector('#hero-footnote-1');
  const chapterStrip = document.querySelector('nav[aria-label="Misconceptions"]');
  const chapters = Array.from(document.querySelectorAll('nav[aria-label="Misconceptions"] a')).map(a => ({
    href: a.getAttribute('href'),
    text: a.textContent.trim()
  }));
  const misconceptionNumbers = Array.from(document.querySelectorAll('[id^="misconception-"]')).map(el => el.id);
  const sup = document.querySelector('h1 sup');
  const supComputed = sup ? getComputedStyle(sup) : null;
  const metaAsides = document.querySelectorAll('[class*="font-mono"]');
  // Check one meta-aside font
  const firstMeta = document.querySelector('p.font-mono') || document.querySelector('aside.font-mono');
  const metaFont = firstMeta ? getComputedStyle(firstMeta).fontFamily : null;

  return {
    h1Text: h1 ? h1.textContent : null,
    hasFootnote: !!footnote,
    hasChapterStrip: !!chapterStrip,
    chapters,
    misconceptionIds: misconceptionNumbers,
    supText: sup ? sup.textContent : null,
    supFontFamily: supComputed ? supComputed.fontFamily : null,
    metaAsideCount: metaAsides.length,
    firstMetaFontFamily: metaFont,
  };
}

