  /* Marketing animations */
  --animate-rerender: rerender 1s ease-in-out 1;
  --animate-highlight: highlight 1s ease-in-out 1;
  --animate-shimmer: shimmer 2s infinite;

  /* Switzer font (loaded via CDN in marketing layout) */
  --font-switzer: "Switzer", system-ui, sans-serif;

  /* JetBrains Mono (loaded via Google Fonts in marketing layout) — */
  /* overrides Tailwind's default font-mono stack so meta-layer copy */
  /* gets a proper editorial monospace face. */
  --font-mono:
    "JetBrains Mono", ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas,
    monospace;
}

/* Marketing keyframes */
@keyframes rerender {
  0% {
    border-color: var(--color-hastoggle-orange);
  }
  40% {
    border-color: var(--color-hastoggle-orange);
  }
}

@keyframes highlight {
  0% {
    background: var(--color-hastoggle-orange);
    color: white;
  }
  40% {
    background: var(--color-hastoggle-orange);
    color: white;
  }
}

@keyframes highlightFadeIn {
  from {
    background-color: transparent;
  }
  to {
    background-color: #808080;
  }
}

@keyframes shimmer {
  0% {
    transform: translateX(-100%);
  }
  100% {
    transform: translateX(100%);
  }
}

@keyframes move-x {
  0% {
    transform: translateX(var(--move-x-from));
  }
  100% {
    transform: translateX(var(--move-x-to));
  }
}

.highlighted-line {
  padding: 2px 8px 2px 0;
  border-radius: 12px;
  animation: highlightFadeIn 0.2s ease-in-out forwards;
}

/* Shiki code syntax highlighting styles */
.shiki {
  color: var(--shiki-light);
  background-color: var(--shiki-light-bg);
  @apply border-border;
}

.shiki span {
  color: var(--shiki-light);
}

.dark .shiki {
  color: var(--shiki-dark);
  background-color: var(--shiki-dark-bg);
}

.dark .shiki span {
  color: var(--shiki-dark);
}

.shiki code {
  display: grid;
  font-size: 13px;
  counter-reset: line;
}

.shiki .line:before {
  content: counter(line);
  counter-increment: line;

  @apply inline-block w-4 mr-8 text-muted-foreground text-right;
}

.shiki[title]:before {
  content: attr(title);
  @apply inline-block text-muted-foreground text-right mb-6 text-sm;
}

