() => {
  const firstMeta = document.querySelector('p.font-mono') || document.querySelector('aside.font-mono');
  const chapter = document.querySelector('nav[aria-label="Misconceptions"] a');
  return {
    metaFont: firstMeta ? getComputedStyle(firstMeta).fontFamily : null,
    chapterFont: chapter ? getComputedStyle(chapter).fontFamily : null,
  };
}

